import { notFound } from "next/navigation";
import Image from "next/image";
import { Mail, Phone, MapPin, Building2, Briefcase, Calendar } from "lucide-react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { EmployeeStatusBadge } from "@/components/employees/employee-status-badge";
import { mockEmployees } from "@/mock/employees";

// Profile Tabs
import { GeneralTab } from "@/components/employees/profile-tabs/general-tab";
import { WorkTab } from "@/components/employees/profile-tabs/work-tab";
import { ContractsTab } from "@/components/employees/profile-tabs/contracts-tab";
import { TimelineTab } from "@/components/employees/profile-tabs/timeline-tab";

interface EmployeeProfilePageProps {
    params: Promise<{
        id: string;
    }>;
}

export async function generateMetadata({ params }: EmployeeProfilePageProps) {
    const resolvedParams = await params;
    const employee = mockEmployees.find((e) => e.id === resolvedParams.id);
    if (!employee) return { title: "Không tìm thấy - Digital HRM" };
    return { title: `${employee.fullName} - Hồ sơ nhân viên | Digital HRM` };
}

export default async function EmployeeProfilePage({ params }: EmployeeProfilePageProps) {
    const resolvedParams = await params;
    const employee = mockEmployees.find((e) => e.id === resolvedParams.id);

    if (!employee) {
        notFound();
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Hồ sơ nhân viên</h1>
                    <p className="text-muted-foreground">
                        Chi tiết thông tin 360° của nhân viên {employee.fullName}.
                    </p>
                </div>
                <div className="flex items-center gap-2">
                    <Button variant="outline">In hồ sơ</Button>
                    <Button>Chỉnh sửa</Button>
                </div>
            </div>

            <Card>
                <CardContent className="p-6">
                    <div className="flex flex-col md:flex-row gap-6 items-start md:items-center">
                        <div className="h-24 w-24 sm:h-32 sm:w-32 rounded-full border-4 border-background bg-primary/10 flex flex-shrink-0 items-center justify-center text-primary font-bold text-3xl sm:text-4xl shadow-sm">
                            {employee.avatar ? (
                                <Image src={employee.avatar} alt={employee.fullName} width={128} height={128} className="rounded-full object-cover" />
                            ) : (
                                employee.fullName.split(' ').pop()?.[0]
                            )}
                        </div>

                        <div className="flex-1 space-y-4">
                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2">
                                <div>
                                    <h2 className="text-2xl sm:text-3xl font-bold flex items-center gap-3">
                                        {employee.fullName}
                                        <EmployeeStatusBadge status={employee.status} />
                                    </h2>
                                    <p className="text-muted-foreground font-medium text-lg mt-1">
                                        {employee.position?.name || 'Chưa cập nhật chức vụ'}
                                    </p>
                                </div>
                                <Badge variant="secondary" className="px-3 py-1 w-fit text-sm">
                                    {employee.employeeCode}
                                </Badge>
                            </div>

                            <Separator />

                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 text-sm">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Building2 className="h-4 w-4" />
                                    <span className="font-medium text-foreground">{employee.department?.name || 'Chưa cập nhật'}</span>
                                </div>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Briefcase className="h-4 w-4" />
                                    <span>Loại HĐ: <span className="font-medium text-foreground">{employee.employmentType === 'FULL_TIME' ? 'Chính thức' : employee.employmentType === 'INTERN' ? 'Thực tập sinh' : 'Thử việc'}</span></span>
                                </div>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Mail className="h-4 w-4" />
                                    <a href={`mailto:${employee.personalEmail}`} className="hover:underline">{employee.personalEmail || 'N/A'}</a>
                                </div>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Phone className="h-4 w-4" />
                                    <a href={`tel:${employee.phone}`} className="hover:underline">{employee.phone || 'N/A'}</a>
                                </div>
                            </div>
                        </div>
                    </div>
                </CardContent>
            </Card>

            <Tabs defaultValue="general" className="w-full">
                <TabsList className="w-full justify-start overflow-x-auto h-auto p-1 bg-muted/50 rounded-lg hidden-scrollbar flex-nowrap">
                    <TabsTrigger value="general" className="rounded-md px-4 py-2">Thông tin chung</TabsTrigger>
                    <TabsTrigger value="work" className="rounded-md px-4 py-2">Công việc</TabsTrigger>
                    <TabsTrigger value="contracts" className="rounded-md px-4 py-2">Hợp đồng</TabsTrigger>
                    <TabsTrigger value="timeline" className="rounded-md px-4 py-2">Lịch sử</TabsTrigger>
                    <TabsTrigger value="leaves" className="rounded-md px-4 py-2" disabled>Nghỉ phép</TabsTrigger>
                    <TabsTrigger value="attendance" className="rounded-md px-4 py-2" disabled>Chấm công</TabsTrigger>
                    <TabsTrigger value="payroll" className="rounded-md px-4 py-2" disabled>Lương</TabsTrigger>
                    <TabsTrigger value="assets" className="rounded-md px-4 py-2" disabled>Tài sản</TabsTrigger>
                </TabsList>

                <div className="mt-6">
                    <TabsContent value="general" className="m-0 focus-visible:outline-none">
                        <GeneralTab employee={employee} />
                    </TabsContent>
                    <TabsContent value="work" className="m-0 focus-visible:outline-none">
                        <WorkTab employee={employee} />
                    </TabsContent>
                    <TabsContent value="contracts" className="m-0 focus-visible:outline-none">
                        <ContractsTab employeeId={employee.id} />
                    </TabsContent>
                    <TabsContent value="timeline" className="m-0 focus-visible:outline-none">
                        <TimelineTab employeeId={employee.id} />
                    </TabsContent>
                </div>
            </Tabs>
        </div>
    );
}

// =============================================================================
// ExportButton — Triggers Excel download of employee data
// =============================================================================

"use client";

import { useState } from 'react';
import { Download, FileSpreadsheet } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { exportEmployeesToExcel } from '@/lib/excel-utils';
import type { Employee } from '@/types';

interface ExportButtonProps {
    employees: Employee[];
    filename?: string;
}

export function ExportButton({ employees, filename = 'danh-sach-nhan-vien' }: ExportButtonProps) {
    const [isExporting, setIsExporting] = useState(false);

    const handleExport = async () => {
        if (employees.length === 0) {
            toast.warning('Không có dữ liệu để xuất');
            return;
        }

        setIsExporting(true);

        try {
            // Small delay for UX feedback
            await new Promise((resolve) => setTimeout(resolve, 300));
            exportEmployeesToExcel(employees, filename);
            toast.success(`Đã xuất ${employees.length} nhân viên ra file Excel thành công`);
        } catch {
            toast.error('Lỗi khi xuất file. Vui lòng thử lại.');
        } finally {
            setIsExporting(false);
        }
    };

    return (
        <Button
            onClick={handleExport}
            disabled={isExporting || employees.length === 0}
            className="gap-2"
            id="export-excel-button"
        >
            {isExporting ? (
                <>
                    <div className="animate-spin rounded-full h-4 w-4 border-2 border-current border-t-transparent" />
                    Đang xuất...
                </>
            ) : (
                <>
                    <Download className="h-4 w-4" />
                    Xuất Excel
                </>
            )}
        </Button>
    );
}

// =============================================================================
// ValidationErrorPanel — Collapsible list of per-row validation errors
// =============================================================================

"use client";

import { useState } from 'react';
import { AlertTriangle, ChevronDown, ChevronUp } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import type { ValidationError } from '@/lib/excel-utils';

interface ValidationErrorPanelProps {
    errors: ValidationError[];
}

export function ValidationErrorPanel({ errors }: ValidationErrorPanelProps) {
    const [isExpanded, setIsExpanded] = useState(true);

    if (errors.length === 0) return null;

    return (
        <div className="rounded-lg border border-destructive/30 bg-destructive/5 dark:bg-destructive/10 overflow-hidden">
            {/* Header */}
            <button
                onClick={() => setIsExpanded(!isExpanded)}
                className="w-full flex items-center justify-between px-4 py-3 hover:bg-destructive/10 transition-colors"
            >
                <div className="flex items-center gap-2">
                    <AlertTriangle className="h-4 w-4 text-destructive shrink-0" />
                    <span className="text-sm font-medium text-destructive">
                        Phát hiện {errors.length} lỗi
                    </span>
                </div>
                <div className="flex items-center gap-2">
                    <Badge variant="destructive" className="text-xs">
                        {errors.length}
                    </Badge>
                    {isExpanded ? (
                        <ChevronUp className="h-4 w-4 text-muted-foreground" />
                    ) : (
                        <ChevronDown className="h-4 w-4 text-muted-foreground" />
                    )}
                </div>
            </button>

            {/* Error list */}
            <div
                className={cn(
                    'transition-all duration-200 overflow-hidden',
                    isExpanded ? 'max-h-[400px]' : 'max-h-0',
                )}
            >
                <div className="border-t border-destructive/20 px-4 py-2 max-h-[380px] overflow-y-auto">
                    <ul className="space-y-1">
                        {errors.map((error, idx) => (
                            <li key={idx} className="flex items-start gap-2 py-1.5 text-sm">
                                <Badge
                                    variant="outline"
                                    className="shrink-0 text-xs font-mono mt-0.5 border-destructive/40 text-destructive"
                                >
                                    Dòng {error.row}
                                </Badge>
                                <span className="text-muted-foreground">{error.message}</span>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
    );
}

import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { EmployeeStatusBadge } from "@/components/employees/employee-status-badge";
import type { Employee } from "@/types";
import { mockWorkHistory } from "@/mock/employees";

interface Props {
    employee: Employee;
}

export function WorkTab({ employee }: Props) {
    const workHistories = mockWorkHistory.filter(wh => wh.employeeId === employee.id).sort((a, b) => new Date(b.startDate).getTime() - new Date(a.startDate).getTime());

    const InfoRow = ({ label, value }: { label: string; value: React.ReactNode }) => (
        <div className="grid grid-cols-1 sm:grid-cols-3 py-3 border-b last:border-0 border-border/50 gap-1 sm:gap-4">
            <div className="text-sm font-medium text-muted-foreground">{label}</div>
            <div className="sm:col-span-2 text-sm text-foreground">{value || <span className="text-muted-foreground italic">Chưa cập nhật</span>}</div>
        </div>
    );

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Thông tin nội bộ */}
            <Card>
                <CardHeader>
                    <CardTitle className="text-lg">Thông tin công việc nội bộ</CardTitle>
                </CardHeader>
                <CardContent>
                    <InfoRow label="Phòng ban" value={<span className="font-medium text-primary">{employee.department?.name}</span>} />
                    <InfoRow label="Chức vụ" value={<span className="font-medium">{employee.position?.name}</span>} />
                    <InfoRow label="Quản lý trực tiếp" value={
                        employee.manager ? (
                            <Link href={`/employees/${employee.manager.id}`} className="flex items-center gap-2 hover:underline text-primary">
                                <div className="h-6 w-6 rounded-full bg-primary/20 flex items-center justify-center text-[10px] font-bold">
                                    {employee.manager.fullName.split(' ').pop()?.[0]}
                                </div>
                                <span>{employee.manager.fullName} - {employee.manager.employeeCode}</span>
                            </Link>
                        ) : <span className="text-muted-foreground">Báo cáo trực tiếp lên Ban Giám đốc</span>
                    } />
                    <InfoRow label="Trạng thái" value={<EmployeeStatusBadge status={employee.status} />} />
                    <InfoRow label="Loại hình" value={
                        <Badge variant="outline">
                            {employee.employmentType === 'FULL_TIME' ? 'Chính thức' :
                                employee.employmentType === 'PART_TIME' ? 'Bán thời gian' :
                                    employee.employmentType === 'INTERN' ? 'Thực tập sinh' : 'Cộng tác viên'}
                        </Badge>
                    } />
                    <InfoRow label="Ngày gia nhập" value={employee.hireDate ? new Date(employee.hireDate).toLocaleDateString('vi-VN') : null} />
                    <InfoRow label="Hết hạn thử việc" value={employee.probationEnd ? new Date(employee.probationEnd).toLocaleDateString('vi-VN') : null} />
                    {employee.resignDate && (
                        <InfoRow label="Ngày nghỉ việc" value={<span className="text-destructive font-medium">{new Date(employee.resignDate).toLocaleDateString('vi-VN')}</span>} />
                    )}
                </CardContent>
            </Card>

            <div className="space-y-6">
                {/* Ngân hàng */}
                <Card>
                    <CardHeader>
                        <CardTitle className="text-lg">Tài khoản Ngân hàng</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <InfoRow label="Tên Ngân hàng" value={employee.bankName} />
                        <InfoRow label="Số tài khoản" value={<span className="font-mono">{employee.bankAccount}</span>} />
                        <InfoRow label="Chi nhánh" value={employee.bankBranch} />
                    </CardContent>
                </Card>

                {/* Thuế & Bảo hiểm */}
                <Card>
                    <CardHeader>
                        <CardTitle className="text-lg">Thuế & Bảo hiểm xã hội</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <InfoRow label="Mã số thuế cá nhân" value={<span className="font-mono">{employee.taxCode}</span>} />
                        <InfoRow label="Số sổ BHXH" value={<span className="font-mono">{employee.socialInsuranceNo}</span>} />
                        <InfoRow label="Số thẻ BHYT" value={<span className="font-mono">{employee.healthInsuranceNo}</span>} />
                    </CardContent>
                </Card>
            </div>

            {/* Kinh nghiệm làm việc */}
            <Card className="lg:col-span-2">
                <CardHeader>
                    <CardTitle className="text-lg">Kinh nghiệm làm việc trước đây</CardTitle>
                </CardHeader>
                <CardContent>
                    {workHistories.length > 0 ? (
                        <div className="relative border-l ml-4 space-y-8 py-2">
                            {workHistories.map((wh, idx) => (
                                <div key={wh.id} className="relative pl-6">
                                    {/* Timeline dot */}
                                    <span className="absolute -left-1.5 top-1.5 h-3 w-3 rounded-full bg-primary ring-4 ring-background" />
                                    <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-1">
                                        <h3 className="text-base font-semibold">{wh.position}</h3>
                                        <time className="text-sm text-muted-foreground font-mono bg-muted px-2 py-0.5 rounded-md">
                                            {new Date(wh.startDate).toLocaleDateString('vi-VN', { month: '2-digit', year: 'numeric' })} -
                                            {wh.endDate ? new Date(wh.endDate).toLocaleDateString('vi-VN', { month: '2-digit', year: 'numeric' }) : 'Hiện tại'}
                                        </time>
                                    </div>
                                    <div className="text-sm font-medium text-primary/80 mb-2">{wh.company}</div>
                                    {wh.description && <p className="text-sm text-muted-foreground">{wh.description}</p>}
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="text-sm text-center py-6 text-muted-foreground">Chưa có thông tin kinh nghiệm làm việc trước đây.</div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

